    if channel.name == 'forwardBackward':
        parent.Rig.MoveForwardBackward(op('magnitudes')['forwardBackward'].eval() * tsPar.eval())
    elif channel.name == 'leftRight':
        parent.Rig.MoveLeftRight(op('magnitudes')['leftRight'].eval() * tsPar.eval())
    elif channel.name == 'pitch':
        parent.Rig.Pitch(op('magnitudes')['pitch'].eval() * rsPar.eval())
    elif channel.name == 'yaw':
        parent.Rig.Yaw(op('magnitudes')['yaw'].eval() * -rsPar.eval())
    elif channel.name == 'up':
        parent.Rig.MoveUpDown(op('magnitudes')['up'].eval() * tsPar.eval())
    elif channel.name == 'down':
        parent.Rig.MoveUpDown(op('magnitudes')['down'].eval() * -tsPar.eval())

def onToOff(channel, sampleIndex, val, prev):
    if channel.name == 'reset':
        parent.Rig.Reset()
    return

